1	import { useState, useEffect, useRef } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { Card } from "@/components/ui/card";
4	import { Button } from "@/components/ui/button";
5	import { Input } from "@/components/ui/input";
6	import { Label } from "@/components/ui/label";
7	import { Switch } from "@/components/ui/switch";
8	import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
9	import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
10	import { supabase } from "@/integrations/supabase/client";
11	import { Settings as SettingsIcon, Camera, Languages, Shield, TriangleAlert, Trash2 } from "lucide-react";
12	import SecurityTab from "@/components/settings/SecurityTab";
13	import {
14	  Select,
15	  SelectContent,
16	  SelectItem,
17	  SelectTrigger,
18	  SelectValue,
19	} from "@/components/ui/select";
20	import {
21	  Dialog,
22	  DialogContent,
23	  DialogHeader,
24	  DialogTitle,
25	  DialogDescription,
26	} from "@/components/ui/dialog";
27	import { languages } from "@/data/countries";
28	import { useToast } from "@/hooks/use-toast";
29	import { useLanguage } from "@/i18n/LanguageContext";
30	
31	const Settings = () => {
32	  const { toast } = useToast();
33	  const { language, setLanguage, t } = useLanguage();
34	  const navigate = useNavigate();
35	  const [profile, setProfile] = useState<any>(null);
36	  const [userType, setUserType] = useState<string | null>(null);
37	  const [uploading, setUploading] = useState(false);
38	  const [saving, setSaving] = useState(false);
39	  const [deleteOpen, setDeleteOpen] = useState(false);
40	  const [deleteInput, setDeleteInput] = useState("");
41	  const [deleting, setDeleting] = useState(false);
42	  const fileInputRef = useRef<HTMLInputElement>(null);
43	
44	  // Editable form fields
45	  const [displayName, setDisplayName] = useState("");
46	  const [email, setEmail] = useState("");
47	  const [handle, setHandle] = useState("");
48	  const [bio, setBio] = useState("");
49	
50	  // Privacy settings
51	  const [profilePublic, setProfilePublic] = useState(true);
52	  const [doNotDisturb, setDoNotDisturb] = useState(false);
53	  const [savingPrivacy, setSavingPrivacy] = useState(false);
54	
55	  useEffect(() => {
56	    checkAuth();
57	  }, []);
58	
59	  const checkAuth = async () => {
60	    const { data: { session } } = await supabase.auth.getSession();
61	    if (!session) return;
62	
63	    const { data: profileData } = await supabase
64	      .from("profiles")
65	      .select("*")
66	      .eq("id", session.user.id)
67	      .single();
68	
69	    setProfile(profileData);
70	    setUserType(profileData?.user_type || null);
71	    setDisplayName(profileData?.display_name || "");
72	    setEmail(profileData?.email || "");
73	    setHandle(profileData?.handle || "");
74	    setBio(profileData?.bio || "");
75	    setProfilePublic(profileData?.profile_public !== false);
76	    setDoNotDisturb(!!profileData?.do_not_disturb);
77	  };
78	
79	  const handleAvatarClick = () => {
80	    fileInputRef.current?.click();
81	  };
82	
83	  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
84	    try {
85	      const file = event.target.files?.[0];
86	      if (!file) return;
87	
88	      if (!file.type.startsWith('image/')) {
89	        toast({ title: "Invalid file type", description: "Please upload an image file", variant: "destructive" });
90	        return;
91	      }
92	
93	      if (file.size > 5 * 1024 * 1024) {
94	        toast({ title: "File too large", description: "Please upload an image smaller than 5MB", variant: "destructive" });
95	        return;
96	      }
97	
98	      setUploading(true);
99	
100	      const { data: { session } } = await supabase.auth.getSession();
101	      if (!session) return;
102	
103	      const fileExt = file.name.split('.').pop()?.toLowerCase() || 'jpg';
104	      // Fixed path per user so upsert overwrites cleanly and RLS folder check passes
105	      const filePath = `${session.user.id}/avatar.${fileExt}`;
106	
107	      const { error: uploadError } = await supabase.storage
108	        .from('avatars')
109	        .upload(filePath, file, { upsert: true });
110	
111	      if (uploadError) throw uploadError;
112	
113	      const { data: { publicUrl } } = supabase.storage
114	        .from('avatars')
115	        .getPublicUrl(filePath);
116	
117	      // Cache-buster so the browser doesn't serve the stale image after an overwrite
118	      const bustedUrl = `${publicUrl}?t=${Date.now()}`;
119	
120	      const { error: updateError } = await supabase
121	        .from('profiles')
122	        .update({ avatar_url: bustedUrl })
123	        .eq('id', session.user.id);
124	
125	      if (updateError) throw updateError;
126	
127	      setProfile({ ...profile, avatar_url: bustedUrl });
128	      toast({ title: "Profile picture updated", description: "Your profile picture has been updated successfully" });
129	    } catch (error) {
130	      console.error('Error uploading avatar:', error);
131	      toast({ title: "Upload failed", description: "Failed to upload profile picture. Please try again.", variant: "destructive" });
132	    } finally {
133	      setUploading(false);
134	    }
135	  };
136	
137	  const handleSave = async () => {
138	    try {
139	      setSaving(true);
140	      const { data: { session } } = await supabase.auth.getSession();
141	      if (!session) return;
142	
143	      const { error } = await supabase
144	        .from('profiles')
145	        .update({
146	          display_name: displayName || null,
147	          handle: handle,
148	          bio: bio || null,
149	        })
150	        .eq('id', session.user.id);
151	
152	      if (error) throw error;
153	
154	      setProfile({ ...profile, display_name: displayName, handle, bio });
155	      toast({ title: "Settings saved", description: "Your account settings have been updated." });
156	    } catch (error: any) {
157	      console.error('Error saving settings:', error);
158	      toast({ title: "Save failed", description: error.message || "Failed to save settings.", variant: "destructive" });
159	    } finally {
160	      setSaving(false);
161	    }
162	  };
163	
164	  const handlePrivacyToggle = async (field: "profile_public" | "do_not_disturb", value: boolean) => {
165	    if (field === "profile_public") setProfilePublic(value);
166	    else setDoNotDisturb(value);
167	    setSavingPrivacy(true);
168	    try {
169	      const { data: { session } } = await supabase.auth.getSession();
170	      if (!session) return;
171	      const { error } = await supabase.from("profiles").update({ [field]: value }).eq("id", session.user.id);
172	      if (error) throw error;
173	      toast({
174	        title: field === "profile_public"
175	          ? (value ? "Profile is now public" : "Profile is now private")
176	          : (value ? "Do Not Disturb on" : "Do Not Disturb off"),
177	        description: field === "profile_public"
178	          ? (value ? "Anyone can view your public profile." : "Your profile is hidden from public view.")
179	          : (value ? "Notifications are paused." : "You'll receive notifications again."),
180	      });
181	    } catch (err: any) {
182	      toast({ title: "Failed to save", description: err.message, variant: "destructive" });
183	      if (field === "profile_public") setProfilePublic(!value);
184	      else setDoNotDisturb(!value);
185	    } finally {
186	      setSavingPrivacy(false);
187	    }
188	  };
189	
190	  const handleDeleteAccount = async () => {
191	    setDeleting(true);
192	    try {
193	      const { error } = await supabase.rpc("delete_user");
194	      if (error) throw error;
195	      await supabase.auth.signOut();
196	      toast({ title: t("settings.deleteAccountSuccess"), description: t("settings.deleteAccountSuccessDesc") });
197	      navigate("/");
198	    } catch (err: any) {
199	      toast({ title: t("settings.deleteAccountError"), description: err.message, variant: "destructive" });
200	    } finally {
201	      setDeleting(false);
202	      setDeleteOpen(false);
203	      setDeleteInput("");
204	    }
205	  };
206	
207	  return (
208	    <div className="container mx-auto px-3 md:px-6 py-6 md:py-8 max-w-5xl">
209	      <div className="flex items-center gap-2 md:gap-3 mb-1 md:mb-2">
210	        <SettingsIcon className="w-6 h-6 md:w-8 md:h-8 text-bronze" />
211	        <h1 className="font-vollkorn text-2xl md:text-4xl font-bold">{t("settings.title")}</h1>
212	      </div>
213	      <p className="text-sm md:text-base text-muted-foreground mb-6 md:mb-8">{t("settings.subtitle")}</p>
214	
215	      <Tabs defaultValue="account" className="w-full">
216	        <TabsList className="grid w-full grid-cols-3 mb-6 md:mb-8 h-auto">
217	          <TabsTrigger value="account" className="text-xs sm:text-sm py-2">{t("settings.account")}</TabsTrigger>
218	          <TabsTrigger value="security" className="text-xs sm:text-sm py-2 gap-1">
219	            <Shield className="w-3.5 h-3.5 hidden sm:inline" />
220	            Security
221	          </TabsTrigger>
222	          <TabsTrigger value="privacy" className="text-xs sm:text-sm py-2">{t("settings.privacy")}</TabsTrigger>
223	        </TabsList>
224	
225	        <TabsContent value="security">
226	          <SecurityTab />
227	        </TabsContent>
228	
229	        <TabsContent value="account">
230	          <Card className="p-4 md:p-8">
231	            <h2 className="font-vollkorn text-xl md:text-2xl font-bold mb-4 md:mb-6">{t("settings.accountInfo")}</h2>
232	            <div className="space-y-4 md:space-y-6">
233	              {/* Profile Picture */}
234	              <div className="flex flex-col items-center gap-4 pb-4 border-b">
235	                <div className="relative">
236	                  <Avatar className="h-24 w-24 md:h-32 md:w-32">
237	                    <AvatarImage src={profile?.avatar_url} />
238	                    <AvatarFallback className="bg-bronze text-white text-2xl md:text-3xl">
239	                      {displayName?.charAt(0) || email?.charAt(0) || "U"}
240	                    </AvatarFallback>
241	                  </Avatar>
242	                  <button
243	                    onClick={handleAvatarClick}
244	                    disabled={uploading}
245	                    className="absolute bottom-0 right-0 bg-bronze hover:bg-bronze-dark text-white rounded-full p-2 shadow-lg transition-colors disabled:opacity-50"
246	                    aria-label="Change profile picture"
247	                  >
248	                    <Camera className="h-4 w-4 md:h-5 md:w-5" />
249	                  </button>
250	                  <input
251	                    ref={fileInputRef}
252	                    type="file"
253	                    accept="image/*"
254	                    onChange={handleFileChange}
255	                    className="hidden"
256	                  />
257	                </div>
258	                <div className="text-center">
259	                  <p className="text-sm text-muted-foreground">
260	                    {uploading ? t("settings.uploading") : t("settings.profilePicture")}
261	                  </p>
262	                  <p className="text-xs text-muted-foreground mt-1">
263	                    {t("settings.maxSize")}
264	                  </p>
265	                </div>
266	              </div>
267	
268	              <div>
269	                <Label htmlFor="displayName" className="text-sm md:text-base">{t("settings.displayName")}</Label>
270	                <Input
271	                  id="displayName"
272	                  value={displayName}
273	                  onChange={(e) => setDisplayName(e.target.value)}
274	                  className="mt-2 h-10 md:h-11"
275	                  placeholder={t("settings.displayNamePlaceholder")}
276	                />
277	              </div>
278	              <div>
279	                <Label htmlFor="email" className="text-sm md:text-base">{t("settings.email")}</Label>
280	                <Input
281	                  id="email"
282	                  type="email"
283	                  value={email}
284	                  readOnly
285	                  className="mt-2 h-10 md:h-11 opacity-60 cursor-not-allowed"
286	                  placeholder={t("settings.emailPlaceholder")}
287	                />
288	                <p className="text-xs text-muted-foreground mt-1">Email cannot be changed here.</p>
289	              </div>
290	              <div>
291	                <Label htmlFor="username" className="text-sm md:text-base">{t("settings.username")}</Label>
292	                <Input
293	                  id="username"
294	                  value={handle}
295	                  onChange={(e) => setHandle(e.target.value)}
296	                  className="mt-2 h-10 md:h-11"
297	                  placeholder={t("settings.usernamePlaceholder")}
298	                />
299	              </div>
300	              <div>
301	                <Label htmlFor="bio" className="text-sm md:text-base">{t("settings.bio")}</Label>
302	                <textarea
303	                  id="bio"
304	                  value={bio}
305	                  onChange={(e) => setBio(e.target.value)}
306	                  className="mt-2 w-full min-h-[80px] md:min-h-[100px] p-3 text-sm md:text-base rounded-md border border-input bg-background placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2 resize-none"
307	                  placeholder={t("settings.bioPlaceholder")}
308	                  maxLength={160}
309	                />
310	                <p className="text-xs text-muted-foreground mt-1">
311	                  {bio.length}/160 — {t("settings.bioMax")}
312	                </p>
313	              </div>
314	              {/* Language */}
315	              <div className="pt-4 border-t">
316	                <div className="flex items-center gap-2 mb-3">
317	                  <Languages className="w-5 h-5 text-bronze" />
318	                  <Label className="text-sm md:text-base">{t("settings.language")}</Label>
319	                </div>
320	                <Select value={language} onValueChange={(val) => {
321	                  setLanguage(val);
322	                  toast({ title: t("toast.languageChanged"), description: t("toast.languageChangedDesc") });
323	                }}>
324	                  <SelectTrigger className="w-full md:w-80 h-11">
325	                    <SelectValue placeholder="Select language" />
326	                  </SelectTrigger>
327	                  <SelectContent>
328	                    {languages.map((lang) => (
329	                      <SelectItem key={lang.code} value={lang.code}>
330	                        <span className="mr-2">{lang.flag}</span> {lang.name}
331	                      </SelectItem>
332	                    ))}
333	                  </SelectContent>
334	                </Select>
335	                <p className="text-xs md:text-sm text-muted-foreground mt-2">{t("settings.languageDesc")}</p>
336	              </div>
337	
338	              <div className="pt-2 border-t">
339	                <Button
340	                  onClick={handleSave}
341	                  disabled={saving}
342	                  className="w-full sm:w-auto bg-bronze hover:bg-bronze-dark text-sm md:text-base px-6 py-5 md:py-6"
343	                >
344	                  {saving ? "Saving..." : t("common.save")}
345	                </Button>
346	              </div>
347	
348	              {/* Danger Zone */}
349	              <div className="pt-4 border-t border-destructive/20">
350	                <div className="flex items-center gap-2 mb-3">
351	                  <TriangleAlert className="w-5 h-5 text-destructive" />
352	                  <h3 className="text-sm md:text-base font-semibold text-destructive">{t("settings.dangerZone")}</h3>
353	                </div>
354	                <div className="rounded-xl border border-destructive/30 bg-destructive/5 p-4 flex flex-col sm:flex-row sm:items-center gap-3 justify-between">
355	                  <div>
356	                    <p className="text-sm font-medium text-foreground">{t("settings.deleteAccount")}</p>
357	                    <p className="text-xs text-muted-foreground mt-0.5 max-w-sm">{t("settings.dangerZoneDesc")}</p>
358	                  </div>
359	                  <Button
360	                    variant="destructive"
361	                    onClick={() => setDeleteOpen(true)}
362	                    className="flex-shrink-0 gap-2 h-11"
363	                  >
364	                    <Trash2 className="h-4 w-4" />
365	                    {t("settings.deleteAccount")}
366	                  </Button>
367	                </div>
368	              </div>
369	            </div>
370	          </Card>
371	
372	          {/* Delete Account Dialog */}
373	          <Dialog open={deleteOpen} onOpenChange={(v) => { setDeleteOpen(v); if (!v) setDeleteInput(""); }}>
374	            <DialogContent className="sm:max-w-md">
375	              <DialogHeader>
376	                <DialogTitle className="flex items-center gap-2 text-destructive font-vollkorn text-xl">
377	                  <TriangleAlert className="h-5 w-5" />
378	                  {t("settings.deleteAccountConfirmTitle")}
379	                </DialogTitle>
380	                <DialogDescription className="text-sm leading-relaxed pt-1">
381	                  {t("settings.deleteAccountConfirmDesc")}
382	                </DialogDescription>
383	              </DialogHeader>
384	              <div className="space-y-4 pt-2">
385	                <div>
386	                  <Label className="text-sm font-medium">{t("settings.deleteAccountConfirmLabel")}</Label>
387	                  <Input
388	                    value={deleteInput}
389	                    onChange={(e) => setDeleteInput(e.target.value)}
390	                    placeholder={t("settings.deleteAccountConfirmPlaceholder")}
391	                    className="mt-1.5 h-11 text-base font-mono border-destructive/40 focus-visible:ring-destructive/30"
392	                    autoComplete="off"
393	                    spellCheck={false}
394	                  />
395	                </div>
396	                <div className="flex gap-3">
397	                  <Button variant="outline" onClick={() => setDeleteOpen(false)} className="flex-1 h-11">
398	                    {t("common.cancel")}
399	                  </Button>
400	                  <Button
401	                    variant="destructive"
402	                    disabled={deleteInput !== "DELETE" || deleting}
403	                    onClick={handleDeleteAccount}
404	                    className="flex-1 h-11 gap-2"
405	                  >
406	                    <Trash2 className="h-4 w-4" />
407	                    {deleting ? "Deleting…" : t("settings.deleteAccountConfirm")}
408	                  </Button>
409	                </div>
410	              </div>
411	            </DialogContent>
412	          </Dialog>
413	        </TabsContent>
414	
415	
416	        <TabsContent value="privacy">
417	          <Card className="p-4 md:p-8">
418	            <h2 className="font-vollkorn text-xl md:text-2xl font-bold mb-4 md:mb-6">{t("settings.privacySettings")}</h2>
419	            <div className="space-y-4 md:space-y-6">
420	              <div className="flex items-start md:items-center justify-between gap-3">
421	                <div className="flex-1 min-w-0">
422	                  <Label className="text-sm md:text-base">{t("settings.profileVisibility")}</Label>
423	                  <p className="text-xs md:text-sm text-muted-foreground mt-0.5">{t("settings.profileVisibilityDesc")}</p>
424	                </div>
425	                <Switch
426	                  checked={profilePublic}
427	                  disabled={savingPrivacy}
428	                  onCheckedChange={(v) => handlePrivacyToggle("profile_public", v)}
429	                  className="flex-shrink-0"
430	                />
431	              </div>
432	              <div className="flex items-start md:items-center justify-between gap-3">
433	                <div className="flex-1 min-w-0">
434	                  <Label className="text-sm md:text-base">{t("settings.doNotDisturb")}</Label>
435	                  <p className="text-xs md:text-sm text-muted-foreground mt-0.5">{t("settings.doNotDisturbDesc")}</p>
436	                </div>
437	                <Switch
438	                  checked={doNotDisturb}
439	                  disabled={savingPrivacy}
440	                  onCheckedChange={(v) => handlePrivacyToggle("do_not_disturb", v)}
441	                  className="flex-shrink-0"
442	                />
443	              </div>
444	            </div>
445	          </Card>
446	        </TabsContent>
447	      </Tabs>
448	    </div>
449	  );
450	};
451	
452	export default Settings;
