1	import { useState, useEffect } from "react";
2	import { useNavigate } from "react-router-dom";
3	import { supabase } from "@/integrations/supabase/client";
4	import { format, subMonths, startOfMonth, endOfMonth } from "date-fns";
5	import {
6	  AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer,
7	  CartesianGrid, BarChart, Bar, Cell, Legend,
8	} from "recharts";
9	import {
10	  LayoutDashboard, Users, CreditCard, FileText, MessageSquare,
11	  Settings, Shield, CheckCircle, XCircle, Search, Menu,
12	  LogOut, Loader2, X, Receipt, FileCheck, ChevronRight,
13	  TrendingUp, TrendingDown, Minus, ArrowUpRight, Palette,
14	  RotateCcw, Trash2, Copy, Mail, Database, Key, Bug,
15	} from "lucide-react";
16	import { Button } from "@/components/ui/button";
17	import { Input } from "@/components/ui/input";
18	import { Textarea } from "@/components/ui/textarea";
19	import { toast } from "sonner";
20	import { cn } from "@/lib/utils";
21	
22	// ─── Helpers ──────────────────────────────────────────────────────────────────
23	const KES = (n: number) =>
24	  n >= 1_000_000
25	    ? `KES ${(n / 1_000_000).toFixed(1)}M`
26	    : n >= 1_000
27	    ? `KES ${(n / 1_000).toFixed(1)}K`
28	    : `KES ${Math.round(n).toLocaleString()}`;
29	
30	const fmt = (n: number) =>
31	  n >= 1_000_000 ? `${(n / 1_000_000).toFixed(1)}M`
32	  : n >= 1_000   ? `${(n / 1_000).toFixed(1)}K`
33	  : String(n);
34	
35	type Section = "overview" | "users" | "billing" | "documents" | "customization" | "support" | "settings" | "security";
36	
37	const planChip = (plan: string | null) => cn(
38	  "text-[10px] font-semibold px-2 py-0.5 rounded-full",
39	  plan === "pro" || plan === "creative_pro" ? "bg-emerald-500/20 text-emerald-400"
40	  : plan === "enterprise"                  ? "bg-violet-500/20  text-violet-400"
41	  : plan === "business" || plan === "brand_workspace" ? "bg-amber-500/20 text-amber-400"
42	  : "bg-white/[0.07] text-white/30"
43	);
44	
45	const statusChip = (s: string) => cn(
46	  "text-[10px] font-semibold px-2 py-0.5 rounded-full",
47	  s === "paid" || s === "signed" || s === "completed" || s === "success"
48	    ? "bg-emerald-500/20 text-emerald-400"
49	  : s === "overdue" || s === "cancelled" || s === "failed"
50	    ? "bg-red-500/20 text-red-400"
51	  : s === "sent"
52	    ? "bg-blue-500/20 text-blue-400"
53	  : "bg-amber-500/20 text-amber-400"
54	);
55	
56	// ─── Shared UI ────────────────────────────────────────────────────────────────
57	const Av = ({ url, name, size = "9" }: { url?: string | null; name?: string | null; size?: string }) => (
58	  <div className={`w-${size} h-${size} rounded-full bg-white/10 flex items-center justify-center text-xs text-white/60 flex-shrink-0 overflow-hidden ring-1 ring-white/5`}>
59	    {url
60	      ? <img src={url} alt="" className="w-full h-full object-cover" />
61	      : <span className="font-semibold">{(name?.[0] || "?").toUpperCase()}</span>}
62	  </div>
63	);
64	
65	const Spin = () => (
66	  <div className="flex items-center justify-center h-64">
67	    <Loader2 className="w-5 h-5 text-bronze animate-spin" />
68	  </div>
69	);
70	
71	const Trend = ({ pct }: { pct: number | null }) => {
72	  if (pct === null) return <span className="text-[10px] text-white/20 font-medium">—</span>;
73	  if (pct === 0)    return (
74	    <span className="flex items-center gap-0.5 text-[10px] text-white/30 font-semibold">
75	      <Minus className="w-3 h-3" /> 0%
76	    </span>
77	  );
