1	import { useState } from "react";
2	import { supabase } from "@/integrations/supabase/client";
3	import { Button } from "@/components/ui/button";
4	import { Card } from "@/components/ui/card";
5	import { Shield, CheckCircle2, Loader2, Mail } from "lucide-react";
6	import { useToast } from "@/hooks/use-toast";
7	import { InputOTP, InputOTPGroup, InputOTPSlot } from "@/components/ui/input-otp";
8	
9	interface MFASetupProps {
10	  onComplete: () => void;
11	  onSkip?: () => void;
12	}
13	
14	const MFASetup = ({ onComplete, onSkip }: MFASetupProps) => {
15	  const { toast } = useToast();
16	  const [step, setStep] = useState<"intro" | "sent" | "done">("intro");
17	  const [email, setEmail] = useState("");
18	  const [code, setCode] = useState("");
19	  const [isLoading, setIsLoading] = useState(false);
20	  const [isSending, setIsSending] = useState(false);
21	
22	  const sendCode = async () => {
23	    setIsSending(true);
24	    try {
25	      const { data: { user } } = await supabase.auth.getUser();
26	      if (!user?.email) throw new Error("No email found on your account.");
27	
28	      setEmail(user.email);
29	
30	      const { error } = await supabase.auth.signInWithOtp({
31	        email: user.email,
32	        options: { shouldCreateUser: false },
33	      });
34	      if (error) throw error;
35	
36	      setStep("sent");
37	      toast({
38	        title: "Code sent",
39	        description: `We sent a 6-digit code to ${user.email}`,
40	      });
41	    } catch (err: any) {
42	      toast({ title: "Error", description: err.message, variant: "destructive" });
43	    } finally {
44	      setIsSending(false);
45	    }
46	  };
47	
48	  const verifyAndEnable = async () => {
49	    if (code.length !== 6) return;
50	    setIsLoading(true);
51	    try {
52	      const { error } = await supabase.auth.verifyOtp({
53	        email,
54	        token: code,
55	        type: "email",
56	      });
57	      if (error) throw error;
58	
59	      await supabase.auth.updateUser({
60	        data: { two_fa_enabled: true, two_fa_method: "email" },
61	      });
62	
63	      // Unenroll any old TOTP factors from the previous setup
64	      const { data: factors } = await supabase.auth.mfa.listFactors();
65	      if (factors?.totp?.length) {
66	        for (const factor of factors.totp) {
67	          await supabase.auth.mfa.unenroll({ factorId: factor.id });
68	        }
69	      }
70	
71	      setStep("done");
72	      setTimeout(onComplete, 1500);
73	    } catch (err: any) {
74	      toast({
75	        title: "Invalid code",
76	        description: "The code you entered is incorrect. Please try again.",
77	        variant: "destructive",
78	      });
79	      setCode("");
80	    } finally {
81	      setIsLoading(false);
82	    }
83	  };
84	
85	  return (
86	    <Card className="p-6 max-w-md mx-auto">
87	      {step === "intro" && (
88	        <div className="text-center">
89	          <div className="w-16 h-16 rounded-full bg-bronze/10 flex items-center justify-center mx-auto mb-4">
90	            <Shield className="w-8 h-8 text-bronze" />
91	          </div>
92	          <h3 className="font-vollkorn text-xl font-bold mb-2">Enable Two-Factor Authentication</h3>
93	          <p className="text-muted-foreground text-sm mb-6">
94	            Every time you sign in, we'll send a 6-digit code to your email. No authenticator app needed.
95	          </p>
96	          <div className="flex flex-col gap-3">
97	            <Button
98	              onClick={sendCode}
99	              disabled={isSending}
100	              className="bg-bronze hover:bg-bronze/90 text-background"
101	            >
102	              {isSending
103	                ? <Loader2 className="w-4 h-4 animate-spin mr-2" />
104	                : <Mail className="w-4 h-4 mr-2" />}
105	              Send Verification Code
106	            </Button>
107	            {onSkip && (
108	              <Button variant="ghost" onClick={onSkip} className="text-muted-foreground">
109	                Skip for now
110	              </Button>
111	            )}
112	          </div>
113	        </div>
114	      )}
115	
116	      {step === "sent" && (
117	        <div className="text-center">
118	          <div className="w-16 h-16 rounded-full bg-bronze/10 flex items-center justify-center mx-auto mb-4">
119	            <Mail className="w-8 h-8 text-bronze" />
120	          </div>
121	          <h3 className="font-vollkorn text-xl font-bold mb-2">Check your email</h3>
122	          <p className="text-muted-foreground text-sm mb-1">We sent a 6-digit code to</p>
123	          <p className="font-medium text-sm mb-6">{email}</p>
124	
125	          <div className="flex justify-center mb-6">
126	            <InputOTP
127	              maxLength={6}
128	              value={code}
129	              onChange={setCode}
130	              onComplete={verifyAndEnable}
131	              autoFocus
132	            >
133	              <InputOTPGroup>
134	                <InputOTPSlot index={0} />
135	                <InputOTPSlot index={1} />
136	                <InputOTPSlot index={2} />
137	                <InputOTPSlot index={3} />
138	                <InputOTPSlot index={4} />
139	                <InputOTPSlot index={5} />
140	              </InputOTPGroup>
141	            </InputOTP>
142	          </div>
143	
144	          <Button
145	            onClick={verifyAndEnable}
146	            disabled={isLoading || code.length !== 6}
147	            className="w-full bg-bronze hover:bg-bronze/90 text-background mb-3"
148	          >
149	            {isLoading && <Loader2 className="w-4 h-4 animate-spin mr-2" />}
150	            Verify & Enable 2FA
151	          </Button>
152	          <button
153	            onClick={sendCode}
154	            disabled={isSending}
155	            className="text-sm text-muted-foreground hover:text-foreground transition-colors"
156	          >
157	            {isSending ? "Sending..." : "Didn't get it? Resend code"}
158	          </button>
159	        </div>
160	      )}
161	
162	      {step === "done" && (
163	        <div className="text-center">
164	          <div className="w-16 h-16 rounded-full bg-green-500/10 flex items-center justify-center mx-auto mb-4">
165	            <CheckCircle2 className="w-8 h-8 text-green-500" />
166	          </div>
167	          <h3 className="font-vollkorn text-xl font-bold mb-2">2FA Enabled!</h3>
168	          <p className="text-muted-foreground text-sm">
169	            Your account is now secured. You'll receive an email code each time you sign in.
170	          </p>
171	        </div>
172	      )}
173	    </Card>
174	  );
175	};
176	
177	export default MFASetup;
