1	-- ── delete_user() RPC ─────────────────────────────────────────────────────────
2	-- Allows an authenticated user to permanently delete their own account.
3	-- Deletes all user data across public tables, then removes the auth.users row.
4	-- SECURITY DEFINER runs with the privileges of the function owner (postgres).
5	-- ─────────────────────────────────────────────────────────────────────────────
6	CREATE OR REPLACE FUNCTION public.delete_user()
7	RETURNS void
8	LANGUAGE plpgsql
9	SECURITY DEFINER
10	SET search_path = public, auth
11	AS $$
12	DECLARE
13	  uid uuid := auth.uid();
14	BEGIN
15	  IF uid IS NULL THEN
16	    RAISE EXCEPTION 'not_authenticated';
17	  END IF;
18	
19	  -- Kira data
20	  DELETE FROM public.kira_messages      WHERE conversation_id IN (
21	    SELECT id FROM public.kira_conversations WHERE user_id = uid
22	  );
23	  DELETE FROM public.kira_conversations WHERE user_id = uid;
24	  DELETE FROM public.kira_projects      WHERE user_id = uid;
25	
26	  -- Canvas / invoices
27	  DELETE FROM public.invoice_items      WHERE invoice_id IN (
28	    SELECT id FROM public.invoices WHERE user_id = uid
29	  );
30	  DELETE FROM public.invoices           WHERE user_id = uid;
31	  DELETE FROM public.canvases           WHERE user_id = uid;
32	
33	  -- Crevia Link
34	  DELETE FROM public.link_buttons       WHERE link_profile_id IN (
35	    SELECT id FROM public.link_profiles WHERE user_id = uid
36	  );
37	  DELETE FROM public.link_social_icons  WHERE link_profile_id IN (
38	    SELECT id FROM public.link_profiles WHERE user_id = uid
39	  );
40	  DELETE FROM public.link_featured_work WHERE link_profile_id IN (
41	    SELECT id FROM public.link_profiles WHERE user_id = uid
42	  );
43	  DELETE FROM public.link_profiles      WHERE user_id = uid;
44	
45	  -- Workspace / messaging
46	  DELETE FROM public.chat_messages      WHERE sender_id = uid;
47	  DELETE FROM public.message_reactions  WHERE user_id = uid;
48	  DELETE FROM public.favorite_messages  WHERE user_id = uid;
49	  DELETE FROM public.deleted_messages   WHERE user_id = uid;
50	  DELETE FROM public.pinned_messages    WHERE pinned_by = uid;
51	  DELETE FROM public.chat_read_receipts WHERE user_id = uid;
52	  DELETE FROM public.room_encrypted_keys WHERE user_id = uid;
53	  DELETE FROM public.chat_room_members  WHERE user_id = uid;
54	
55	  -- Campaigns / payments
56	  DELETE FROM public.campaign_applications WHERE creator_id = uid;
57	  DELETE FROM public.deliverable_submissions WHERE creator_id = uid;
58	  DELETE FROM public.escrow_payments    WHERE creator_id = uid OR brand_id = uid;
59	  DELETE FROM public.payment_transactions WHERE user_id = uid;
60	  DELETE FROM public.creator_payout_methods WHERE user_id = uid;
61	
62	  -- Misc profile data
63	  DELETE FROM public.brand_favorites    WHERE user_id = uid OR creator_id = uid;
64	  DELETE FROM public.wishlist           WHERE user_id = uid;
65	  DELETE FROM public.rate_card_services WHERE rate_card_id IN (
66	    SELECT id FROM public.rate_cards WHERE user_id = uid
67	  );
68	  DELETE FROM public.rate_cards         WHERE user_id = uid;
69	  DELETE FROM public.business_settings  WHERE user_id = uid;
70	  DELETE FROM public.user_encryption_keys WHERE user_id = uid;
71	  DELETE FROM public.creator_profiles   WHERE id = uid;
72	  DELETE FROM public.brand_profiles     WHERE id = uid;
73	  DELETE FROM public.profiles           WHERE id = uid;
74	
75	  -- Finally delete the auth user (cascades to auth.sessions etc.)
76	  DELETE FROM auth.users WHERE id = uid;
77	END;
78	$$;
